mapper.select:
SELECT COUNT(NBB.BOARD_SEQ) FROM NMCP_BOARD_BAS NBB, ( SELECT AA.ATT_SEQ AS ATT_SEQ , AA.FILE_PATH_NM AS FILE_PATH_NM , AA.FILE_TYPE AS FILE_TYPE , AA.FILE_CAPA AS FILE_CAPA , AA.BOARD_SEQ FROM NMCP_BOARD_ATT_DTL AA, ( SELECT MAX (ATT_SEQ) AS ATT_SEQ, BOARD_SEQ FROM NMCP_BOARD_ATT_DTL GROUP BY BOARD_SEQ) BB WHERE AA.ATT_SEQ = BB.ATT_SEQ AND AA.BOARD_SEQ = BB.BOARD_SEQ) NBAD WHERE 1=1 AND NBB.BOARD_SEQ = NBAD.BOARD_SEQ(+) AND NBB.BOARD_CTG_SEQ = #{boardCtgSeq} AND NBB.VIEW_YN = 'Y' AND NBB.BOARD_SEQ NOT IN ( SELECT BOARD_SEQ FROM ( SELECT BOARD_SEQ FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq} AND NOTI_YN = 'Y' AND VIEW_YN = 'Y' ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC ) A WHERE ROWNUM <= 5 )
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND NBB.SBST_CTG = #{sbstCtg}
AND NBB.SBST_SUB_CTG_CD = #{sbstSubCtgCd}

SELECT BOARD_NUM, BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, SBST_SUB_CTG_CD, BOARD_SUBJECT, BOARD_CONTENTS, BOARD_WRITER_NM, IMG_NM, VIEW_YN, NOTI_YN, BOARD_WRITE_DT, BOARD_ATT_YN, ATT_SEQ, FILE_PATH_NM, FILE_TYPE, FILE_CAPA, BOARD_HIT_CNT FROM ( SELECT ROW_NUMBER() OVER(ORDER BY NBB.BOARD_WRITE_DT, NBB.BOARD_SEQ) AS BOARD_NUM, NBB.BOARD_SEQ, NBB.BOARD_CTG_SEQ, NBB.SBST_CTG, NBB.SBST_SUB_CTG_CD, NBB.BOARD_SUBJECT, NBB.BOARD_CONTENTS, NBB.BOARD_WRITER_NM, NBB.IMG_NM, NBB.VIEW_YN, NBB.NOTI_YN, NBB.BOARD_HIT_CNT, TO_CHAR(NBB.BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, NBB.BOARD_ATT_YN, NBAD.ATT_SEQ, NBAD.FILE_PATH_NM, NBAD.FILE_TYPE, NBAD.FILE_CAPA FROM NMCP_BOARD_BAS NBB, ( SELECT AA.ATT_SEQ AS ATT_SEQ , AA.FILE_PATH_NM AS FILE_PATH_NM , AA.FILE_TYPE AS FILE_TYPE , AA.FILE_CAPA AS FILE_CAPA , AA.BOARD_SEQ FROM NMCP_BOARD_ATT_DTL AA, ( SELECT MAX (ATT_SEQ) AS ATT_SEQ, BOARD_SEQ FROM NMCP_BOARD_ATT_DTL GROUP BY BOARD_SEQ) BB WHERE AA.ATT_SEQ = BB.ATT_SEQ AND AA.BOARD_SEQ = BB.BOARD_SEQ) NBAD WHERE 1=1 AND NBB.BOARD_SEQ = NBAD.BOARD_SEQ(+) AND NBB.BOARD_CTG_SEQ = #{boardCtgSeq} AND NBB.VIEW_YN = 'Y' AND NBB.BOARD_SEQ NOT IN ( SELECT BOARD_SEQ FROM ( SELECT BOARD_SEQ FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq} AND NOTI_YN = 'Y' AND VIEW_YN = 'Y' ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC ) A WHERE ROWNUM <= 5 )
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND NBB.SBST_CTG = #{sbstCtg}
AND NBB.SBST_SUB_CTG_CD = #{sbstSubCtgCd}
)
ORDER BY BOARD_HIT_CNT DESC
ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC

SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, SBST_SUB_CTG_CD, IMG_NM, BOARD_SUBJECT, BOARD_CONTENTS, BOARD_WRITER_NM, VIEW_YN, NOTI_YN, BOARD_WRITE_DT, BOARD_ATT_YN FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, SBST_SUB_CTG_CD, IMG_NM, BOARD_SUBJECT, BOARD_CONTENTS, BOARD_WRITER_NM, VIEW_YN, NOTI_YN, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq} AND NOTI_YN = 'Y' AND VIEW_YN = 'Y'
AND SBST_CTG = #{sbstCtg}
AND SBST_SUB_CTG_CD = #{sbstSubCtgCd}
ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC ) A WHERE ROWNUM <= 5

SELECT BOARD_SEQ , BOARD_CTG_SEQ , SBST_CTG , SBST_SUB_CTG_CD , BOARD_SUBJECT , BOARD_WRITER_NM , BOARD_CONTENTS , NOTI_YN , VIEW_YN , IMG_NM , BOARD_WRITE_DT , BOARD_ATT_YN , CRET_DT , NEXT_SEQ , NEXT_SUBJECT , NEXT_DT , PRE_SEQ , PRE_SUBJECT , PRE_DT FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, SBST_SUB_CTG_CD, BOARD_SUBJECT, BOARD_CONTENTS, BOARD_WRITER_NM, NOTI_YN, IMG_NM, VIEW_YN, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, CRET_DT, lead(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SEQ, lead(BOARD_SUBJECT,1,'다음글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SUBJECT, lead(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_DT, lag(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SEQ, lag(BOARD_SUBJECT,1,'이전글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SUBJECT, lag(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_DT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq}
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND SBST_CTG = #{sbstCtg}
AND SBST_SUB_CTG_CD = #{sbstSubCtgCd}
AND NOTI_YN = 'N' AND VIEW_YN = 'Y' ) WHERE BOARD_SEQ = #{boardSeq}
